mapper.select:
/* SQL ID : ExamOathMapper.select 설 명 : 시험 서약서 조회 */ SELECT A.TKEXAM_OATH_ID AS oathCd , A.CRS_SMSTR_ID AS termCd , A.ORG_ID AS orgId , A.DGRS_YR AS haksaYear , A.DGRS_SMSTR AS haksaTerm , A.USER_ID AS userId , A.MID_EXAM_OATHYN AS midOath , A.END_OATH AS endOath , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm FROM TB_LMS_TKEXAM_OATH AS A WHERE 1 = 1
AND A.TKEXAM_OATH_ID = #{oathCd}
AND A.CRS_SMSTR_ID = #{termCd}
AND A.DGRS_YR = #{haksaYear}
AND A.DGRS_SMSTR = #{haksaTerm}
AND A.USER_ID = #{userId}

mapper.insert:
		/*
             SQL ID : ExamOathMapper.insert
             	설  명 : 시험 서약서 등록
         */
    	INSERT INTO TB_LMS_TKEXAM_OATH (
    		  TKEXAM_OATH_ID
			, CRS_SMSTR_ID
			, ORG_ID
			, DGRS_YR
			, DGRS_SMSTR
			, USER_ID
			, MID_EXAM_OATHYN
			, END_OATH
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
    	) VALUES (
    		  #{oathCd}
    		, #{termCd}
    		, #{orgId}
    		, #{haksaYear}
    		, #{haksaTerm}
    		, #{userId}
    		, #{midOath}
    		, #{endOath}
    		, #{rgtrId}
    		, FN_DTTM()
    		, #{mdfrId}
    		, FN_DTTM()
    	)

mapper.select:
/* SQL ID : ExamOathMapper.listOathByCreCrsPaging 설 명 : 과목별 시험 서약서 제출 목록 조회 */ SELECT ROW_NUMBER() OVER(ORDER BY A.FRST_INQ_DTTM) AS lineNo , A.TKEXAM_OATH_ID AS oathCd , A.CRS_SMSTR_ID AS termCd , A.ORG_ID AS orgId , A.DGRS_YR AS haksaYear , A.DGRS_SMSTR AS haksaTerm , A.USER_ID AS userId , A.MID_EXAM_OATHYN AS midOath , A.END_OATH AS endOath , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm , IFNULL(B.DEPTNM, D.DEPTNM) AS deptNm , C.USERNM AS userNm , (SELECT COUNT(STD_ID) FROM TB_LMS_ATNDLC_SBJCT WHERE ATNDLC_STSCD NOT IN('D', 'T') AND SBJCT_ID = #{crsCreCd}) AS totStdCnt , B.STD_ID AS stdNo FROM TB_LMS_TKEXAM_OATH AS A JOIN TB_LMS_ATNDLC_SBJCT AS B ON A.USER_ID = B.USER_ID AND B.ATNDLC_STSCD NOT IN('D', 'T') JOIN TB_LMS_USR AS C ON B.USER_ID = C.USER_ID LEFT JOIN TB_HOME_USER_DEPT_CD AS D ON C.DEPT_CD = D.DEPT_CD WHERE B.SBJCT_ID = #{crsCreCd}
AND A.DGRS_YR = #{haksaYear}
AND A.DGRS_SMSTR = #{haksaTerm}
AND ( LOWER(IFNULL(B.DEPTNM, D.DEPTNM)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(B.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(C.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
ORDER BY A.FRST_INQ_DTTM DESC
LIMIT #{firstIndex}, #{listScale}
